import copy


def apply_patch(document, operations):
    doc = copy.deepcopy(document)
    for operation in operations:
        op = operation["op"]
        path = operation["path"]
        value = operation.get("value")

        parts = path.split("/")
        if parts and parts[0] == "":
            parts = parts[1:]

        current = doc
        for part in parts[:-1]:
            if isinstance(current, list):
                current = current[int(part)]
            else:
                current = current[part]

        key = parts[-1]

        if op == "add":
            if isinstance(current, list):
                if key == "-":
                    current.append(value)
                else:
                    current.insert(int(key), value)
            else:
                current[key] = value
        elif op == "replace":
            if isinstance(current, list):
                current[int(key)] = value
            else:
                current[key] = value
        elif op == "remove":
            if isinstance(current, list):
                del current[int(key)]
            else:
                del current[key]

    return doc
